<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
function mrv_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function mrv_date($v){return (!$v||$v==='0000-00-00')?'-':date('d M Y',strtotime($v));}
function mrv_valid_date($v,$f){return preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$v)?$v:$f;}
function mrv_status_class($s){$m=array('DRAFT'=>'warning','SUBMITTED'=>'info','MANAGER_APPROVED'=>'primary','HR_REVIEW'=>'primary','APPROVED'=>'success','REJECTED'=>'danger','RETURNED'=>'warning','CANCELLED'=>'default','CLOSED'=>'success');return isset($m[$s])?$m[$s]:'default';}
function mrv_priority_class($s){$m=array('LOW'=>'default','NORMAL'=>'info','HIGH'=>'warning','URGENT'=>'danger');return isset($m[$s])?$m[$s]:'default';}
$today=date('Y-m-d');$from=mrv_valid_date(isset($_GET['tgl_awal'])?$_GET['tgl_awal']:'',date('Y-01-01'));$to=mrv_valid_date(isset($_GET['tgl_akhir'])?$_GET['tgl_akhir']:'',$today);$filterCat=isset($_GET['request_category'])?trim($_GET['request_category']):'';$filterStatus=isset($_GET['status'])?trim($_GET['status']):'';$filterPriority=isset($_GET['priority'])?trim($_GET['priority']):'';
$cats=array('EMPLOYEE_DATA','CERTIFICATE','CLAIM','BENEFIT','PAYROLL','ATTENDANCE_CORRECTION','DOCUMENT','FACILITY','OTHER');$statuses=array('DRAFT','SUBMITTED','MANAGER_APPROVED','HR_REVIEW','APPROVED','REJECTED','RETURNED','CANCELLED','CLOSED');$priorities=array('LOW','NORMAL','HIGH','URGENT');
$uid=isset($_SESSION['id_user'])?(int)$_SESSION['id_user']:0;$employee=$uid>0?$db->fetch("SELECT e.*,u.foto_user,d.nm_dept,j.job_title_name,m.employee_no manager_no,m.full_name manager_name FROM erp_employee_master e LEFT JOIN sys_users u ON u.id=e.user_id LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title j ON j.id=e.job_title_id LEFT JOIN erp_employee_master m ON m.id=e.manager_employee_id WHERE e.user_id=? LIMIT 1",array($uid)):null;
$rows=array();$summary=array('total'=>0,'pending'=>0,'approved'=>0,'exception'=>0,'closed'=>0);$catChart=array();$statusChart=array();
if($employee){$where=" WHERE r.employee_id=? AND r.request_date BETWEEN ? AND ? ";$p=array((int)$employee->id,$from,$to);if($filterCat!==''){$where.=" AND r.request_category=? ";$p[]=$filterCat;}if($filterStatus!==''){$where.=" AND r.workflow_status=? ";$p[]=$filterStatus;}if($filterPriority!==''){$where.=" AND r.priority=? ";$p[]=$filterPriority;}
  $s=$db->fetch("SELECT COUNT(*) total,SUM(workflow_status IN ('SUBMITTED','MANAGER_APPROVED','HR_REVIEW')) pending,SUM(workflow_status='APPROVED') approved,SUM(workflow_status IN ('REJECTED','RETURNED','CANCELLED')) exception,SUM(workflow_status='CLOSED') closed FROM erp_employee_request r $where",$p);if($s)foreach($summary as $k=>$v)$summary[$k]=isset($s->$k)?(float)$s->$k:0;
  $st=$db->query("SELECT r.*,a.employee_no approver_no,a.full_name approver_name FROM erp_employee_request r LEFT JOIN erp_employee_master a ON a.id=r.approver_employee_id $where ORDER BY r.request_date DESC,r.request_no DESC",$p);$rows=$st?$st->fetchAll(PDO::FETCH_OBJ):array();
  $cr=$db->query("SELECT request_category label,COUNT(*) total FROM erp_employee_request r $where GROUP BY request_category",$p);foreach($cr as $r)$catChart[]=array($r->label,(int)$r->total);if(!$catChart)$catChart[]=array('No Data',0);
  $sr=$db->query("SELECT workflow_status label,COUNT(*) total FROM erp_employee_request r $where GROUP BY workflow_status",$p);foreach($sr as $r)$statusChart[]=array($r->label,(int)$r->total);if(!$statusChart)$statusChart[]=array('No Data',0);
}
$photoUrl=$employee?erpkb_user_photo_url($employee->foto_user,'back_profil_foto'):base_admin().'assets/dist/img/default-user-neutral.svg';
?>
