after{content:' *';color:#dd4b39}.select2-container{width:100%!important}#modal_my_request .modal-body{max-height:calc(100vh - 185px);overflow-y:auto}@media(max-width:767px){.mr-actions{margin-left:0}.mr-chart{height:245px}}</style>
