<div class="box mr-card"><div class="box-header"><h3 class="box-title"><i class="fa fa-list"></i> Riwayat My Request</h3></div><div class="box-body table-responsive"><table id="dtb_my_request" class="table table-bordered table-hover mr-table" style="width:100%"><thead><tr><th>Request</th><th>Subject</th><th><?=hr_h('hr_date', 'Date');?></th><th>Priority</th><th>Approver</th><th><?=hr_h('common_status', 'Status');?></th><th><?=hr_h('common_action', 'Action');?></th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><strong><?=mrv_h($r->request_no);?></strong><br><small><?=mrv_h($r->request_category);?></small><br><small><?=mrv_h($r->request_type);?></small></td><td><strong><?=mrv_h($r->subject);?></strong><br><small><?=mrv_h(mb_strimwidth((string)$r->description,0,90,'...'));?></small></td><td><?=mrv_h(mrv_date($r->request_date));?><br><small>Req: <?=mrv_h(mrv_date($r->required_date));?></small></td><td><span class="label label-<?=mrv_priority_class($r->priority);?>"><?=mrv_h($r->priority);?></span></td><td><?=mrv_h($r->approver_no?($r->approver_no.' - '.$r->approver_name):'-');?></td><td><span class="label label-<?=mrv_status_class($r->workflow_status);?>"><?=mrv_h($r->workflow_status);?></span><br><small><?=mrv_h($r->decision);?></small></td><td><button class="btn btn-info btn-xs btn-detail-request" data-id="<?=mrv_h($r->id);?>"><i class="fa fa-eye"></i></button> <?php if(in_array($r->workflow_status,array('DRAFT','RETURNED'),true)): ?><button class="btn btn-primary btn-xs btn-edit-request" data-id="<?=mrv_h($r->id);?>"><i class="fa fa-pencil"></i></button><?php endif; ?> <?php if(!in_array($r->workflow_status,array('APPROVED','REJECTED','CANCELLED','CLOSED'),true)): ?><button class="btn btn-warning btn-xs btn-cancel-request" data-id="<?=mrv_h($r->id);?>" data-no="<?=mrv_h($r->request_no);?>"><i class="fa fa-ban"></i></button><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div></div>
<div id="modal_my_request" class="modal fade"><div class="modal-dialog modal-lg" style="width:92%"><div class="modal-content"><form id="formMyRequest"><input type="hidden" name="id" id="mr_id"><input type="hidden" name="submit_status" id="mr_submit_status" value="DRAFT"><div class="modal-header"><button class="close" data-dismiss="modal">&times;</button><h4 class="modal-title"><i class="fa fa-plus"></i> Create Request</h4></div><div class="modal-body"><div class="alert alert-info"><b>Tips:</b> Save Draft untuk menyimpan sementara. Submit Request untuk mengirim ke manager/HR.</div><div class="row"><div class="col-md-3 form-group"><label><?=hr_h('hr_employee', 'Employee');?></label><input class="form-control" value="<?=mrv_h($employee->employee_no.' - '.$employee->full_name);?>" readonly></div><div class="col-md-3 form-group"><label><?=hr_h('hr_department', 'Department');?></label><input class="form-control" value="<?=mrv_h($employee->department_code.' - '.$employee->nm_dept);?>" readonly></div><div class="col-md-3 form-group"><label><?=hr_h('hr_manager', 'Manager');?></label><input class="form-control" value="<?=mrv_h($employee->manager_no?($employee->manager_no.' - '.$employee->manager_name):'-');?>" readonly></div><div class="col-md-3 form-group"><label>Request Date</label><input name="request_date" id="mr_request_date" class="form-control mr-date" value="<?=date('Y-m-d');?>"></div></div><div class="row"><div class="col-md-3 form-group"><label class="required-label">Category</label><select name="request_category" id="mr_request_category" class="form-control mr-select2-modal"><?php foreach($cats as $c): ?><option><?=$c;?></option><?php endforeach; ?></select></div><div class="col-md-3 form-group"><label class="required-label">Request Type</label><input name="request_type" id="mr_request_type" class="form-control" placeholder="Misal: Surat Kerja / Update Alamat"></div><div class="col-md-2 form-group"><label>Priority</label><select name="priority" id="mr_priority" class="form-control mr-select2-modal"><?php foreach($priorities as $p): ?><option><?=$p;?></option><?php endforeach; ?></select></div><div class="col-md-2 form-group"><label>Required Date</label><input name="required_date" id="mr_required_date" class="form-control mr-date"></div><div class="col-md-2 form-group"><label>Attachment Ref</label><input name="attachment_ref" id="mr_attachment_ref" class="form-control"></div></div><div class="form-group"><label class="required-label">Subject</label><input name="subject" id="mr_subject" class="form-control"></div><div class="form-group"><label class="required-label"><?=hr_h('hr_description', 'Description');?></label><textarea name="description" id="mr_description" class="form-control" rows="4"></textarea></div><div class="form-group"><label><?=hr_h('common_remarks', 'Remarks');?></label><textarea name="remarks" id="mr_remarks" class="form-control" rows="2"></textarea></div><div id="mr_form_error" class="alert alert-danger" style="display:none"></div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal">Batal</button><button type="button" class="btn btn-info btn-save-request" data-status="DRAFT"><i class="fa fa-save"></i> Save Draft</button><button type="button" class="btn btn-primary btn-save-request" data-status="SUBMITTED"><i class="fa fa-send"></i> Submit Request</button></div></form></div></div></div>
