<?php if($employee): ?><script src="<?=base_url();?>assets/js/highcharts.js"></script><script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script><script>
function mrReset(){document.getElementById('formMyRequest').reset();$('#mr_id').val('');$('#mr_submit_status').val('DRAFT');$('#mr_request_date').val('<?=date('Y-m-d');?>');$('#mr_request_category').val('OTHER').trigger('change');$('#mr_priority').val('NORMAL').trigger('change');$('#mr_form_error').hide().text('');$('#modal_my_request .modal-title').html('<i class="fa fa-plus"></i> Create Request')}
$(function(){if($.fn.datepicker)$('.mr-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});if($.fn.select2){$('.mr-select2').select2({width:'100%',allowClear:true});$('.mr-select2-modal').select2({width:'100%',dropdownParent:$('#modal_my_request')})}if($.fn.DataTable)$('#dtb_my_request').DataTable({pageLength:25,order:[[2,'desc']],columnDefs:[{targets:[6],orderable:false}]});$('#btnAddMyRequest').click(function(){mrReset();$('#modal_my_request').modal({backdrop:'static',keyboard:false})});$('#btnExportMyRequest').click(function(){window.location='<?=base_admin();?>modul/my_request/my_request_action.php?act=export&'+$('#formFilterMyRequest').serialize()});$('.btn-save-request').click(function(){var b=$(this);$('#mr_submit_status').val(b.data('status'));$('#mr_form_error').hide().text('');b.prop('disabled',true);$.post('<?=base_admin();?>modul/my_request/my_request_action.php?act=save',$('#formMyRequest').serialize(),function(r){b.prop('disabled',false);if(r.status==='good'){$('#modal_my_request').modal('hide');Swal.fire('Saved',r.message,'success').then(function(){location.reload()})}else $('#mr_form_error').text(r.error_message||'Gagal menyimpan.').show()},'json').fail(function(x){b.prop('disabled',false);$('#mr_form_error').text(x.responseText||'Gagal menyimpan.').show()})});$(document).on('click','.btn-edit-request',function(){mrReset();$.post('<?=base_admin();?>modul/my_request/my_request_action.php?act=get',{id:$(this).data('id')},function(r){if(r.status!=='good'){Swal.fire('Error',r.error_message,'error');return}var d=r.data;$('#mr_id').val(d.id);$('#mr_request_date').val(d.request_date);$('#mr_request_category').val(d.request_category).trigger('change');$('#mr_request_type').val(d.request_type);$('#mr_priority').val(d.priority).trigger('change');$('#mr_required_date').val(d.required_date);$('#mr_attachment_ref').val(d.attachment_ref);$('#mr_subject').val(d.subject);$('#mr_description').val(d.description);$('#mr_remarks').val(d.remarks);$('#modal_my_request .modal-title').html('<i class="fa fa-pencil"></i> Edit Request '+d.request_no);$('#modal_my_request').modal({backdrop:'static',keyboard:false})},'json')});$(document).on('click','.btn-detail-request',function(){$('#mr_detail_body').html('<div class="text-center text-muted"><i class="fa fa-spinner fa-spin"></i> Loading...</div>');$('#modal_mr_detail').modal('show');$.post('<?=base_admin();?>modul/my_request/my_request_action.php?act=detail',{id:$(this).data('id')},function(h){$('#mr_detail_body').html(h)})});$(document).on('click','.btn-cancel-request',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:'Cancel request?',text:no,input:'textarea',inputPlaceholder:'Alasan cancel',showCancelButton:true,confirmButtonText:'Cancel Request'}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/my_request/my_request_action.php?act=cancel',{id:id,reason:x.value||''},function(r){if(r.status==='good')Swal.fire('Cancelled',r.message,'success').then(function(){location.reload()});else Swal.fire('Error',r.error_message,'error')},'json')})});Highcharts.setOptions({lang:{thousandsSep:','},colors:['#0891b2','#2563eb','#0f766e','#f59e0b','#dc2626','#7c3aed','#64748b']});Highcharts.chart('mr_cat_chart',{chart:{type:'pie'},title:{text:null},plotOptions:{pie:{innerSize:'58%',dataLabels:{enabled:true,format:'{point.name}: {point.y}'}}},series:[{name:'Category',data:<?=json_encode($catChart);?>}],credits:{enabled:false}});Highcharts.chart('mr_status_chart',{chart:{type:'bar'},title:{text:null},xAxis:{type:'category'},yAxis:{title:{text:'Request'},allowDecimals:false},legend:{enabled:false},series:[{name:'Status',data:<?=json_encode($statusChart);?>}],credits:{enabled:false}})});
</script><?php endif; ?>
